import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { minify } from "terser";

const scriptDir = path.dirname(fileURLToPath(import.meta.url));
const projectRoot = path.resolve(scriptDir, "..");

const jsFiles = [
  "js/data/site-config.js",
  "js/data/component-registry.js",
  "js/data/products-data.js",
  "js/pages/landing-loader.js",
  "js/pages/static-page.js",
  "js/pages/app-page.js",
  "js/core/menu.js",
  "js/core/reveal.js",
  "js/core/api.js",
  "js/pages/product-page.js",
  "js/core/main.js",
];

function stripGeneratedHeader(source) {
  return source.replace(/^\/\/ Generated by[^\n]*\n/, "");
}

const sources = await Promise.all(
  jsFiles.map(async (file) => {
    const source = await readFile(path.join(projectRoot, file), "utf8");
    return `;\n${stripGeneratedHeader(source).trim()}`;
  })
);

const outputPath = path.join(projectRoot, "js/app.min.js");
const minified = await minify(sources.join("\n"), {
  compress: true,
  mangle: true,
  format: {
    comments: false,
  },
});

if (!minified.code) {
  throw new Error("Failed to minify JS bundle");
}

await mkdir(path.dirname(outputPath), { recursive: true });
await writeFile(outputPath, minified.code, "utf8");

console.log(`JS bundle created at ${path.relative(projectRoot, outputPath)}`);
